  return (
    <Application title="Blog" subtitle={post.title}>
      <article style={{ maxWidth: '720px', padding: '2rem' }}>
        <header>
          <Text as="h1" sx={{ fontSize: 4, mb: 2 }}>{post.title}</Text>
          <Text as="p" color="fg.muted" sx={{ mb: 3 }}>
